mapper.select:
SELECT p.product_no, p.product_no AS id, p.company_no, p.product_name, p.product_name AS name, p.product_details, p.product_details AS content, p.original_price, p.original_price AS price, p.is_active, p.img_url, p.img_url AS thumbnail, p.large_category, p.medium_category, p.deposit, p.reg_date, c.com_name FROM product p LEFT JOIN company c ON p.company_no = c.company_no
INNER JOIN product_tag_map ptm ON p.product_no = ptm.product_no INNER JOIN product_tag pt ON ptm.tag_id = pt.id
AND p.large_category = #{largeCategory}
AND p.medium_category = #{mediumCategory}
AND pt.tag IN
#{tag}
GROUP BY p.product_no
HAVING COUNT(DISTINCT pt.tag) = #{tagSize}
ORDER BY p.reg_date DESC
